struct Игрок {
    имя: String,
    здоровье: i32,
}

impl Игрок {
    // &self означает "обращаемся к самому объекту"
    fn показать(&self) {
        println!("Игрок: {}, HP: {}", self.имя, self.здоровье);
    }

    fn получить_урон(&mut self, урон: i32) {
        self.здоровье -= урон;
        println!("{} получил {} урона!", self.имя, урон);
    }
}

fn main() {
    let mut герой = Игрок {
        имя: String::from("Саша"),
        здоровье: 100,
    };
    герой.показать();
    герой.получить_урон(25);
    герой.показать();
}

