fn двигаться(направление: Направление) {
    match направление {
        Направление::Вверх  => println!("Идём вверх! ↑"),
        Направление::Вниз   => println!("Идём вниз! ↓"),
        Направление::Влево  => println!("Идём влево! ←"),
        Направление::Вправо => println!("Идём вправо! →"),
    }
}

enum Фигура {
    Круг(f64),              // радиус
    Прямоугольник(f64, f64), // ширина, высота
    Треугольник(f64, f64, f64), // три стороны
}

fn площадь(фигура: Фигура) -> f64 {
    match фигура {
        Фигура::Круг(r)     => 3.14159 * r * r,
        Фигура::Прямоугольник(ш, в) => ш * в,
        Фигура::Треугольник(a, b, c) => {
            let s = (a + b + c) / 2.0;
            (s * (s-a) * (s-b) * (s-c)).sqrt()
        }
    }
}

