fn найти_победителя(игроки: &[i32]) -> Option<i32> {
    if игроки.is_empty() {
        None  // нет игроков — нет победителя
    } else {
        Some(игроки[0])  // первый игрок — победитель
    }
}

fn main() {
    let победитель = найти_победителя(&[42, 15, 7]);
    match победитель {
        Some(очки) => println!("Победитель набрал {} очков!", очки),
        None       => println!("Игроков нет"),
    }
}

fn main() {
    let число: Option<i32> = Some(42);

    // if let — если это Some, достаём значение
    if let Some(n) = число {
        println!("Число есть: {}", n);
    } else {
        println!("Числа нет");
    }

    // unwrap_or — дать значение по умолчанию
    let пустое: Option<i32> = None;
    let результат = пустое.unwrap_or(0);
    println!("Результат: {}", результат);  // 0
}

fn first_or_zero(opt: Option<i32>) -> i32 {
    opt.unwrap_or(0)
}

fn main() {
    println!("{}", first_or_zero(Some(42)));  // 42
    println!("{}", first_or_zero(None));       // 0
    println!("{}", first_or_zero(Some(-5)));   // -5
}

fn делить(а: f64, б: f64) -> Result<f64, String> {
    if б == 0.0 {
        Err(String::from("Нельзя делить на ноль!"))
    } else {
        Ok(а / б)
    }
}

fn main() {
    match делить(10.0, 2.0) {
        Ok(результат)  => println!("Результат: {}", результат),
        Err(ошибка)    => println!("Ошибка: {}", ошибка),
    }

    match делить(5.0, 0.0) {
        Ok(результат)  => println!("Результат: {}", результат),
        Err(ошибка)    => println!("Ошибка: {}", ошибка),
    }
}

fn парсить_число(текст: &str) -> Result<i32, String> {
    текст.parse::<i32>().map_err(|e| e.to_string())
}

fn посчитать(а: &str, б: &str) -> Result<i32, String> {
    let х = парсить_число(а)?;  // ? = если Err, сразу вернуть ошибку
    let у = парсить_число(б)?;
    Ok(х + у)
}

fn main() {
    println!("{:?}", посчитать("5", "3"));   // Ok(8)
    println!("{:?}", посчитать("5", "abc")); // Err(...)
}

fn main() {
    // Способ 1: пустой вектор
    let mut оценки: Vec<i32> = Vec::new();
    оценки.push(5);  // добавляем элемент
    оценки.push(4);
    оценки.push(5);

    // Способ 2: сразу с данными
    let игры = vec!["Minecraft", "Roblox", "CS:GO"];

    println!("Оценки: {:?}", оценки);
    println!("Игры: {:?}", игры);
}

fn main() {
    let mut числа = vec![10, 20, 30, 40, 50];

    // Получить элемент
    println!("Первый: {}", числа[0]);      // 10
    println!("Третий: {}", числа[2]);      // 30

    // Длина
    println!("Длина: {}", числа.len());    // 5

    // Добавить в конец
    числа.push(60);

    // Удалить последний
    let последний = числа.pop();
    println!("Удалили: {:?}", последний);  // Some(60)

    // Перебрать все
    for n in &числа {
        print!("{} ", n);
    }
}

fn main() {
    let mut числа = vec![3, 1, 4, 1, 5, 9, 2, 6];
    числа.sort();
    println!("Отсортировано: {:?}", числа);
    println!("Сумма: {}", числа.iter().sum::<i32>());
    println!("Максимум: {}", числа.iter().max().unwrap());
}

fn sum_array(nums: Vec<i32>) -> i32 {
    let mut sum = 0;
    for n in &nums {
        sum += n;  // n — ссылка, но += работает с ней
    }
    sum
}

fn main() {
    let v = vec![1, 2, 3, 4, 5];
    println!("Сумма: {}", sum_array(v));  // 15
}

fn sum_array(nums: Vec<i32>) -> i32 {
    nums.iter().sum()
}

fn main() {
    println!("{}", sum_array(vec![1, 2, 3]));  // 6
    println!("{}", sum_array(vec![]));        // 0
}

fn count_positive(nums: Vec<i32>) -> i32 {
    nums.iter().filter(|n| **n > 0).count() as i32
}

fn main() {
    let v = vec![1, -2, 3, 0, 5];
    println!("{}", count_positive(v));  // 3
}

fn find_max(nums: Vec<i32>) -> i32 {
    *nums.iter().max().unwrap()
}

fn main() {
    println!("{}", find_max(vec![1, 5, 3, 9, 2]));  // 9
}

