fn main() {
    // Стек: размер известен на этапе компиляции
    let x: i32 = 42;        // 4 байта на стеке
    let flag: bool = true;   // 1 байт на стеке

    // Куча: размер может меняться
    let s = String::from("Привет");  // данные строки — на куче
    let v = vec![1, 2, 3];           // данные вектора — на куче
}

// Что на самом деле происходит в памяти:
//
//   Стек                    Куча
//   ┌──────────────┐        ┌───┬───┬───┬───┬───┬───┐
//   │ ptr ──────────────────►│ П │ р │ и │ в │ е │ т │
//   │ len: 12      │        └───┴───┴───┴───┴───┴───┘
//   │ capacity: 12 │        (12 байт: 6 символов UTF-8
//   └──────────────┘         по 2 байта каждый)
//
//   let s = String::from("Привет");

fn main() {
    {                                      // начало области видимости
        let s = String::from("Привет");    // s создана
        println!("{}", s);                 // s используется
    }                                      // конец области — s удалена, память свободна!
    // println!("{}", s);  // ❌ Ошибка: s больше не существует
}

fn main() {
    let s1 = String::from("Привет");
    let s2 = s1;  // владение перешло к s2!

    // println!("{}", s1);  // ❌ Ошибка: value used after move
    println!("{}", s2);     // ✅ OK — s2 теперь владелец
}

// После let s2 = s1:
//
//   s1 (НЕДЕЙСТВИТЕЛЬНА)     s2 (ВЛАДЕЛЕЦ)
//   ┌──────────────┐         ┌──────────────┐        Куча
//   │ ptr ─── ✗    │         │ ptr ──────────────────► "Привет"
//   │ len: 12      │         │ len: 12      │
//   │ capacity: 12 │         │ capacity: 12 │
//   └──────────────┘         └──────────────┘
//
//   s1 больше не имеет доступа к данным

fn main() {
    let x = 42;
    let y = x;  // x копируется в y — оба живы!
    println!("x = {}, y = {}", x, y);  // ✅ x = 42, y = 42

    let a = true;
    let b = a;  // bool тоже Copy
    println!("a = {}, b = {}", a, b);  // ✅
}

fn main() {
    let s1 = String::from("Привет");
    let s2 = s1.clone();  // глубокая копия: новый String на куче

    println!("s1 = {}", s1);  // ✅ оба работают
    println!("s2 = {}", s2);  // ✅
}

fn напечатать(s: String) {
    println!("{}", s);
}   // s удаляется здесь — drop!

fn main() {
    let текст = String::from("Привет");
    напечатать(текст);  // владение передано в функцию

    // println!("{}", текст);  // ❌ Ошибка: текст перемещён
}

fn удвоить(n: i32) -> i32 {
    n * 2
}

fn main() {
    let x = 10;
    let y = удвоить(x);  // x копируется в функцию
    println!("x = {}, y = {}", x, y);  // ✅ x по-прежнему 10
}

fn создать_приветствие(имя: &str) -> String {
    format!("Привет, {}!", имя)  // создаём String и возвращаем
}

fn main() {
    let приветствие = создать_приветствие("Аня");
    println!("{}", приветствие);  // ✅ мы владелец
}

fn добавить_восклицание(mut s: String) -> String {
    s.push('!');
    s  // возвращаем владение обратно
}

fn main() {
    let текст = String::from("Привет");
    let текст = добавить_восклицание(текст);  // передали и получили обратно
    println!("{}", текст);  // "Привет!"
}

struct Пользователь {
    имя: String,
    возраст: u32,
}

fn main() {
    let пользователь = Пользователь {
        имя: String::from("Аня"),
        возраст: 25,
    };

    // Если переместить одно поле — вся структура "разбита"
    let имя = пользователь.имя;  // move поля имя
    // println!("{}", пользователь.имя);    // ❌ поле перемещено
    println!("{}", пользователь.возраст);   // ✅ u32 — Copy
    println!("{}", имя);                    // ✅
}

