use std::rc::Rc;

fn main() {
    // Без Rc: перемещение — второй список не может использовать данные
    // let shared = vec![3, 4, 5];
    // let list_a = (vec![1, 2], shared);      // shared перемещён
    // let list_b = (vec![10, 20], shared);    // ❌ Ошибка: shared уже перемещён!

    // С Rc: оба списка владеют одними данными
    let shared = Rc::new(vec![3, 4, 5]);
    let list_a = (vec![1, 2], Rc::clone(&shared));
    let list_b = (vec![10, 20], Rc::clone(&shared));

    println!("A: {:?}, shared: {:?}", list_a.0, list_a.1);
    println!("B: {:?}, shared: {:?}", list_b.0, list_b.1);
    println!("Владельцев: {}", Rc::strong_count(&shared));  // 3
}

use std::rc::Rc;

fn main() {
    let a = Rc::new(String::from("Огромная строка на 1 ГБ"));
    let b = Rc::clone(&a);  // +1 к счётчику, данные НЕ копируются
    let c = Rc::clone(&a);  // +1

    println!("Счётчик: {}", Rc::strong_count(&a));  // 3
    drop(c);                                          // -1
    println!("Счётчик: {}", Rc::strong_count(&a));  // 2
    drop(b);                                          // -1
    println!("Счётчик: {}", Rc::strong_count(&a));  // 1
}  // a удаляется → счётчик 0 → данные освобождаются

