use std::rc::{Rc, Weak};

fn main() {
    let strong = Rc::new(42);
    let weak: Weak<i32> = Rc::downgrade(&strong);  // слабая ссылка

    // Weak не владеет — чтобы использовать, нужно upgrade()
    if let Some(val) = weak.upgrade() {
        println!("Значение: {}", val);  // 42
    }

    drop(strong);  // данные удалены

    // Weak больше не может получить значение
    assert!(weak.upgrade().is_none());
    println!("Данные удалены, weak знает об этом");
}

