    let счётчик = Arc::new(Mutex::new(0));
    let mut потоки = vec![];

    for _ in 0..5 {
        let счётчик = Arc::clone(&счётчик);  // +1 к счётчику ссылок
        let handle = thread::spawn(move || {
            let mut num = счётчик.lock().unwrap();
            *num += 1;
        });
        потоки.push(handle);
    }

    for handle in потоки {
        handle.join().unwrap();
    }

    println!("Итого: {}", *счётчик.lock().unwrap());  // 5
}

